// In FlowCanvas.jsx, add this state
const [testValues, setTestValues] = useState({});
const [selectedInput, setSelectedInput] = useState(null);

// Add this function to set test values
const updateTestValue = (nodeId, value) => {
  setTestValues(prev => ({
    ...prev,
    [nodeId]: value
  }));
};

// Add this UI component near the Submit button
<div style={{
  position: "absolute",
  top: 20,
  left: 20,
  zIndex: 10,
  background: "#fff",
  padding: "12px",
  borderRadius: "8px",
  boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
  minWidth: "200px"
}}>
  <h4 style={{ margin: "0 0 8px 0", fontSize: "14px" }}>Input Test Values</h4>
  {nodes.filter(n => n.type === 'inputNode').map(inputNode => (
    <div key={inputNode.id} style={{ marginBottom: "8px" }}>
      <label style={{ fontSize: "12px", display: "block", marginBottom: "4px" }}>
        {inputNode.data?.inputName || inputNode.id}:
      </label>
      <input
        type="text"
        value={testValues[inputNode.id] || ""}
        onChange={(e) => updateTestValue(inputNode.id, e.target.value)}
        placeholder={`Test value for ${inputNode.data?.inputName}`}
        style={{
          width: "100%",
          padding: "6px",
          fontSize: "12px",
          border: "1px solid #d1d5db",
          borderRadius: "4px"
        }}
      />
    </div>
  ))}
  {nodes.filter(n => n.type === 'inputNode').length === 0 && (
    <div style={{ fontSize: "12px", color: "#6b7280", fontStyle: "italic" }}>
      Add Input Nodes to set test values
    </div>
  )}
</div>
